import React from 'react';
import { useNavigate } from 'react-router-dom';

const CTA = () => {
    const navigate = useNavigate();
    return (
        <section className="py-20 bg-orange-600 text-center text-white">
            <h2 className="text-4xl font-bold mb-6">Siap Memulai Karier Anda?</h2>
            <button 
                onClick={() => navigate('/register')}
                className="px-8 py-3 bg-white text-orange-600 font-bold rounded-lg hover:bg-gray-100 transition"
            >
                Daftar Sekarang
            </button>
        </section>
    );
};
export default CTA;
